mapper.sql:
FROM MENU M
LEFT JOIN ROLE_MENU RM ON M.ROLE_ID = RM.ROLE_ID
LEFT JOIN ROLE R ON RM.ROLE_CD = R.ROLE_CD AND R.PRJ_ID = #{projectId}
LEFT JOIN GRP_ROLE GR ON R.ROLE_CD = GR.ROLE_CD
LEFT JOIN GRP G ON GR.GRP_ID = G.ID AND G.PRJ_ID = #{projectId}

where.if:
AND EXISTS (
  SELECT 1 FROM ROLE_MENU RM_DT
  INNER JOIN ROLE R_DT ON RM_DT.ROLE_CD = R_DT.ROLE_CD AND R_DT.PRJ_ID = #{projectId}
  WHERE RM_DT.ROLE_ID = M.ROLE_ID
    AND TRUNC(R_DT.CREATED_ON) >= TO_DATE(#{createdFrom}, 'YYYY-MM-DD')
)

AND EXISTS (
  SELECT 1 FROM ROLE_MENU RM_DT2
  INNER JOIN ROLE R_DT2 ON RM_DT2.ROLE_CD = R_DT2.ROLE_CD AND R_DT2.PRJ_ID = #{projectId}
  WHERE RM_DT2.ROLE_ID = M.ROLE_ID
    AND TRUNC(R_DT2.CREATED_ON) <= TO_DATE(#{createdTo}, 'YYYY-MM-DD')
)

mapper.select:
SELECT * FROM (
  SELECT p.*, ROWNUM AS rn FROM (
    SELECT
      M.ROLE_ID   AS roleId,
      M.ROLE_NAME AS roleName,
      MAX(R.CREATED_ON) AS createdOn,
      COUNT(DISTINCT G.ID) AS grpCnt

    GROUP BY M.ROLE_ID, M.ROLE_NAME
    ORDER BY M.ROLE_ID
  ) p
  WHERE ROWNUM <= #{offset} + #{limit}
) WHERE rn > #{offset}
